patch:
diff --git a/llvm/lib/Transforms/IPO/FunctionAttrs.cpp b/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
index f918d7e059b6..fe7f63e40fe1 100644
--- a/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
+++ b/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
@@ -677,9 +677,19 @@ ArgumentAccessInfo getArgumentAccessInfo(const Instruction *I,
     auto *ConstantLength = dyn_cast<ConstantInt>(Length);
     if (ConstantLength && Offset &&
         ConstantLength->getValue().isStrictlyPositive()) {
-      return ConstantRange(
-          APInt(64, *Offset, true),
-          APInt(64, *Offset + ConstantLength->getSExtValue(), true));
+      APInt Low(64, *Offset, true);
+      APInt LengthVal = ConstantLength->getValue();
+      // Sign-extend LengthVal to 64 bits if needed
+      if (LengthVal.getBitWidth() < 64)
+        LengthVal = LengthVal.sext(64);
+      else if (LengthVal.getBitWidth() > 64)
+        LengthVal = LengthVal.trunc(64);
+      bool Overflow;
+      APInt High = Low.sadd_ov(LengthVal, Overflow);
+      // Bail if the range overflows signed 64-bit int.
+      if (Overflow)
+        return std::nullopt;
+      return ConstantRange(Low, High);
     }
     return std::nullopt;
   };

